+              )}
+            </div>
+            {icon && (
+              <div className={`${iconColorClasses[color]} opacity-80`}>
+                {icon}
+              </div>
+            )}
+          </div>
+        </CardBody>
+      </Card>
+    </motion.div>
+  );
+}

