+    if (!agent) return;
+
+    const newPosition = embedding instanceof Float32Array
+      ? embedding
+      : new Float32Array(embedding);
+
+    // Calculate velocity
+    for (let i = 0; i < agent.position.length; i++) {
+      agent.velocity[i] = newPosition[i] - agent.position[i];
