+      try {
+        context = await this.executePhase(phaseConfig.type, context, phaseConfig.config);
+        phaseResults.push({
+          phase: phaseConfig.type,
+          success: true,
+          data: this.summarizePhaseData(phaseConfig.type, context),
+          timeMs: performance.now() - phaseStart,
+        });
+      } catch (error: any) {
